"""Baked-in reference data to save weight file slots.

Reference embeddings and class mapping are base64-encoded here
so all 3 weight file slots can be used for ONNX models.
"""

import base64
import json
import numpy as np

_EMBEDDINGS_B64 = """"""

_CLASS_MAPPING_B64 = """"""

_EMB_SHAPE = (357, 1408)


def load_reference_embeddings() -> np.ndarray:
    """Decode and return reference embeddings array."""
    raw = base64.b64decode(_EMBEDDINGS_B64)
    return np.frombuffer(raw, dtype=np.float16).reshape(_EMB_SHAPE)


def load_class_mapping() -> dict[int, int]:
    """Decode and return ImageFolder index -> category_id mapping."""
    raw = base64.b64decode(_CLASS_MAPPING_B64).decode("utf-8")
    data = json.loads(raw)
    return {int(k): int(v) for k, v in data.items()}
